// the same suite.
type chaosBackend struct {
	name string
	make func(*testing.T) Backend
}

func chaosBackends() []chaosBackend {
	return []chaosBackend{
		{name: "jsonl", make: func(t *testing.T) Backend { return newJSONLStore(t) }},
